import { useEffect, useState } from "react";
import { PageShell } from "@/components/orderly/PageShell";
import { Info, Check } from "lucide-react";
import { useTranslation } from "@/i18n";
import { dexLanguageOptions, normalizeLanguageCode } from "@/i18n/languages";
import { storageKey } from "@/utils/storage";

export default function Page() {
  const { t } = useTranslation();
  const [selected, setSelected] = useState<string[]>([]);
  const [toast, setToast] = useState<string | null>(null);

  useEffect(() => {
    const stored = localStorage.getItem(storageKey("orderlyLanguages"));
    if (stored) {
      try {
        const parsed = JSON.parse(stored) as string[];
        setSelected(
          Array.from(
            new Set(
              parsed
                .map(code => normalizeLanguageCode(code))
                .filter(Boolean) as string[]
            )
          )
        );
      } catch {}
    }
  }, []);

  function persist(next: string[]) {
    setSelected(next);
    if (typeof window !== "undefined") {
      localStorage.setItem(
        storageKey("orderlyLanguages"),
        JSON.stringify(
          Array.from(
            new Set(
              next.map(code => normalizeLanguageCode(code)).filter(Boolean)
            )
          )
        )
      );
    }
  }

  function showToast(message: string) {
    setToast(message);
    setTimeout(() => setToast(null), 3000);
  }

  function toggleLanguage(code: string) {
    const isSelected = selected.includes(code);
    if (isSelected) {
      persist(selected.filter(c => c !== code));
    } else {
      persist([...selected, code]);
    }
  }

  function toggleAll() {
    const allSelected = selected.length === dexLanguageOptions.length;
    if (allSelected) {
      persist([]);
      showToast(t("languageSupport.allUnselected"));
    } else {
      persist(dexLanguageOptions.map(l => l.code));
      showToast(t("languageSupport.allSelected"));
    }
  }

  const allSelected = selected.length === dexLanguageOptions.length;

  return (
    <PageShell pageTitle={t("languageSupport.title")}>
      <div className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-primary) p-6">
        <div className="mb-6 flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
          <button
            type="button"
            onClick={toggleAll}
            className="inline-flex items-center justify-center gap-2 rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) px-4 py-2 text-sm font-medium text-(--fg-primary) transition-colors hover:bg-(--bg-hover)"
          >
            {allSelected
              ? t("languageSupport.unselectAll")
              : t("languageSupport.selectAll")}
          </button>
        </div>

        <div className="mb-6 grid grid-cols-2 gap-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5">
          {dexLanguageOptions.map(language => {
            const isSelected = selected.includes(language.code);
            return (
              <button
                key={language.code}
                type="button"
                onClick={() => toggleLanguage(language.code)}
                className={`flex items-center gap-2 rounded-lg border p-2 text-sm transition-all ${
                  isSelected
                    ? "border-(--line-brand) bg-[rgba(188,135,255,0.12)] text-(--fg-brand)"
                    : "border-(--line-subtle) bg-(--bg-input) text-(--fg-primary) hover:border-(--line-strong) hover:bg-(--bg-hover)"
                }`}
              >
                <span className="flex-1 text-left truncate">
                  {language.label}
                </span>
                {isSelected && <Check className="h-4 w-4 shrink-0" />}
              </button>
            );
          })}
        </div>

        {selected.length === 0 && (
          <div className="mb-6 text-center text-sm text-(--fg-secondary)">
            {t("languageSupport.empty")}
          </div>
        )}

        <div className="rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) p-4">
          <div className="mb-2 flex items-center gap-2">
            <Info className="h-4 w-4 text-(--fg-brand)" />
            <span className="text-sm font-medium text-(--fg-primary)">
              {t("languageSupport.aboutTitle")}
            </span>
          </div>
          <ul className="list-disc space-y-1 pl-4 text-xs text-(--fg-secondary)">
            <li>{t("languageSupport.aboutSwitcher")}</li>
            <li>{t("languageSupport.aboutBuiltIn")}</li>
            <li>{t("languageSupport.aboutCustomize")}</li>
            <li>{t("languageSupport.aboutFallback")}</li>
          </ul>
        </div>
      </div>

      {toast && (
        <div className="fixed bottom-5 left-1/2 z-100 -translate-x-1/2 rounded-full border border-(--line-brand) bg-(--bg-surface-primary) px-5 py-2.5 text-sm font-medium text-(--fg-primary) shadow-xl">
          {toast}
        </div>
      )}
    </PageShell>
  );
}
